args.sparql:
SELECT ?athlete ?sport WHERE {
  wd:Q91568 p:P361 ?eventStatement.
  ?eventStatement ps:P361 ?event.
  ?event wdt:P523 ?eventFirstYear.
  FILTER (YEAR(?eventFirstYear) = 2002)
  ?event wdt:P2742 ?sport.
  ?athlete wdt:P1393 ?event;
           wdt:P1318 wd:Q15015;
           wdt:P27 wd:Q183.
}
